import{_ as e,o,c as r,ae as a}from"./chunks/framework.CyZiF_rV.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ru/srodowiska.md","filePath":"ru/srodowiska.md"}'),s={name:"ru/srodowiska.md"};function d(n,t,l,p,i,h){return o(),r("div",null,[...t[0]||(t[0]=[a('<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/srodowiska.md" target="_blank" rel="noreferrer">srodowiska.md</a></p></blockquote><h2 id="среды-ksef-api-2-0" tabindex="-1">Среды KSeF API 2.0 <a class="header-anchor" href="#среды-ksef-api-2-0" aria-label="Permalink to &quot;Среды KSeF API 2.0&quot;">​</a></h2><p>15.12.2025</p><p>Ниже приведена информация о публичных средах.</p><table tabindex="0"><thead><tr><th>Аббр.</th><th>Среда</th><th>Описание</th><th>Документация API</th><th>Допустимые форматы</th></tr></thead><tbody><tr><td><strong>TEST</strong></td><td>Тестовая <br> (Release Candidate)</td><td>Среда для тестирования интеграции с KSeF API 2.0, содержит версии RC.</td><td><a href="https://api-test.ksef.mf.gov.pl/docs/v2" target="_blank" rel="noreferrer">https://api-test.ksef.mf.gov.pl/docs/v2</a></td><td>FA(2), FA(3), FA_PEF (3), FA_KOR_PEF (3)</td></tr><tr><td><strong>DEMO</strong></td><td>Предпродуктовая (Demo)</td><td>Среда, соответствующая продуктовой конфигурации, предназначенная для финальной валидации интеграции в условиях, приближенных к продуктовым.</td><td><a href="https://api-demo.ksef.mf.gov.pl/docs/v2" target="_blank" rel="noreferrer">https://api-demo.ksef.mf.gov.pl/docs/v2</a></td><td>FA(3), FA_PEF (3), FA_KOR_PEF (3)</td></tr><tr><td><strong>PRD</strong></td><td>Продуктовая</td><td>Среда для выставления и получения счетов-фактур с полной юридической силой, с гарантированным SLA и соответствующими продуктовыми данными.</td><td><a href="https://api.ksef.mf.gov.pl/docs/v2" target="_blank" rel="noreferrer">https://api.ksef.mf.gov.pl/docs/v2</a></td><td>FA(3), FA_PEF (3), FA_KOR_PEF (3)</td></tr></tbody></table><blockquote><p>&lt;font color=&quot;red&quot;&gt;Внимание:&lt;/font&gt; Тестовые среды (TE/DEMO) служат исключительно для тестирования интеграции с API KSeF. Не следует отправлять в них <strong>продуктовые счета-фактуры</strong> или реальные данные субъектов.</p></blockquote><p>В тестовой среде <code>TE</code> допустима аутентификация с использованием самоподписанных сертификатов (self-signed), что на практике означает, что многие интеграторы могут <a href="./uwierzytelnianie.html#proces-uwierzytelniania">аутентифицироваться</a> в контексте одной и той же компании. По этой причине данные, введенные в среде <code>TE</code>, не изолированы и могут быть общими между интеграторами. Для тестов следует использовать случайные идентификаторы NIP, избегая любых реальных данных.</p><h3 id="сервисные-работы-в-тестовых-средах" tabindex="-1">Сервисные работы в тестовых средах <a class="header-anchor" href="#сервисные-работы-в-тестовых-средах" aria-label="Permalink to &quot;Сервисные работы в тестовых средах&quot;">​</a></h3><p>В связи с планируемым, систематическим развитием Национальной системы электронных счетов-фактур (KSeF 2.0), <strong>с 1 октября 2025 г.</strong> в тестовых средах Системы могут проводиться циклические сервисные работы.</p><p>Эти работы будут проводиться в часы с <strong>16:00 до 18:00</strong>. В это время могут возникать временные затруднения в доступе к тестовым средам.</p><p>После завершения работ в <a href="./api-changelog.html">changelog</a> будут публиковаться <strong>исключительно изменения, влияющие на интеграцию</strong>, например изменения поведения API, модификации контрактов, схем XSD, лимитов и т.п. Изменения, не влияющие на API и незаметные с точки зрения интеграции, например внутренние исправления качества, производительности, безопасности <strong>могут не сообщаться</strong> или будут представляться в сводном виде.</p>',11)])])}const c=e(s,[["render",d]]);export{g as __pageData,c as default};
